from __future__ import annotations

import json
from dataclasses import dataclass, field
from pathlib import Path
from typing import Dict, List, Optional


@dataclass
class TargetDef:
    name: str
    outputFile: str
    header: str
    detectFiles: List[str] = field(default_factory=list)


