USER_TARGETS_FILE = Path.home() / ".smartctx" / "targets.json"


def load_user_targets() -> Dict[str, TargetDef]:
    if not USER_TARGETS_FILE.exists():
        return {}
    try:
        raw = json.loads(USER_TARGETS_FILE.read_text("utf-8"))
    except (json.JSONDecodeError, OSError):
        return {}

    out: Dict[str, TargetDef] = {}
    for key, value in raw.items():
        if not isinstance(value, dict) or not value.get("outputFile"):
            continue
        out[key] = TargetDef(
            name=value.get("name", key),
            outputFile=value["outputFile"],
            header=value.get("header", f"# {key} \u2014 auto-generated by smartctx"),
            detectFiles=value.get("detectFiles") or [],
        )
    return out


def save_user_targets(targets: Dict[str, TargetDef]) -> None:
    USER_TARGETS_FILE.parent.mkdir(parents=True, exist_ok=True)
    data = {
        k: {
            "name": v.name,
            "outputFile": v.outputFile,
            "header": v.header,
            "detectFiles": v.detectFiles,
        }
        for k, v in targets.items()
    }
    USER_TARGETS_FILE.write_text(json.dumps(data, indent=2), "utf-8")


def get_all_targets() -> Dict[str, TargetDef]:
    merged = dict(BUILT_IN_TARGETS)
    merged.update(load_user_targets())
    return merged


def get_target(name: str) -> Optional[TargetDef]:
    return get_all_targets().get(name.lower())


def add_user_target(definition: TargetDef) -> None:
    user = load_user_targets()
    user[definition.name.lower()] = definition
    save_user_targets(user)


def remove_user_target(name: str) -> bool:
    key = name.lower()
    user = load_user_targets()
    if key not in user:
        return False
    del user[key]
    save_user_targets(user)
    return True


def parse_targets(value: str) -> List[str]:
    return [s.strip().lower() for s in value.split(",") if s.strip()]


def detect_target(project_path: str) -> Optional[str]:
    root = Path(project_path)
    for key, definition in get_all_targets().items():
        for marker in definition.detectFiles or []:
            if (root / marker).exists():
                return key
    return None
